status_t BlockDevice::readBlock(uint64_t lba, void* buf, size_t len) {
    if (!buf || len == 0)
        return STATUS_INVALID_ARG;
    if (lba >= m_capacity)
        return STATUS_OUT_OF_RANGE;
    auto rc = m_backend->read(lba, buf, len);
    if (rc != STATUS_OK)
        m_errorCount++;
    return rc;
}
